const grouped = {};
for (const item of $input.all()) {
  const cnpj = item.json.emp_cnpj_raiz || '';
  const key = `${item.json.dre_linha_seq}_${item.json.dre_linha_descri}_${cnpj}`;
  if (!grouped[key]) {
    grouped[key] = {
      visao_id: item.json.visao_id,
      cliente_id: item.json.cliente_id,
      crg_periodo: item.json.crg_periodo,
      dre_linha_seq: item.json.dre_linha_seq,
      dre_linha_descri: item.json.dre_linha_descri,
      dre_linha_visivel: item.json.dre_linha_visivel,
      dre_linha_valor: item.json.dre_linha_valor,
      estilo_linha_id: item.json.estilo_linha_id,
      est_nivel_ident: item.json.est_nivel_ident,
      est_tipg_tela: item.json.est_tipg_tela,
      perc_ref: item.json.perc_ref,
      cnpj_raiz: cnpj,
      conta_janeiro:0,conta_fevereiro:0,conta_marco:0,conta_abril:0,
      conta_maio:0,conta_junho:0,conta_julho:0,conta_agosto:0,
      conta_setembro:0,conta_outubro:0,conta_novembro:0,conta_dezembro:0,
      conta_acumulado:0
    };
  }
  if (item.json.perc_ref !== '#L%%') {
    grouped[key].conta_janeiro   += item.json.conta_janeiro   || 0;
    grouped[key].conta_fevereiro += item.json.conta_fevereiro || 0;
    grouped[key].conta_marco     += item.json.conta_marco     || 0;
    grouped[key].conta_abril     += item.json.conta_abril     || 0;
    grouped[key].conta_maio      += item.json.conta_maio      || 0;
    grouped[key].conta_junho     += item.json.conta_junho     || 0;
    grouped[key].conta_julho     += item.json.conta_julho     || 0;
    grouped[key].conta_agosto    += item.json.conta_agosto    || 0;
    grouped[key].conta_setembro  += item.json.conta_setembro  || 0;
    grouped[key].conta_outubro   += item.json.conta_outubro   || 0;
    grouped[key].conta_novembro  += item.json.conta_novembro  || 0;
    grouped[key].conta_dezembro  += item.json.conta_dezembro  || 0;
    grouped[key].conta_acumulado += item.json.conta_acumulado || 0;
  }
}
const result = Object.values(grouped).sort((a,b) => {
  if (a.dre_linha_seq !== b.dre_linha_seq) return a.dre_linha_seq - b.dre_linha_seq;
  return a.cnpj_raiz.localeCompare(b.cnpj_raiz);
});
const colunas = ['conta_janeiro','conta_fevereiro','conta_marco','conta_abril','conta_maio','conta_junho','conta_julho','conta_agosto','conta_setembro','conta_outubro','conta_novembro','conta_dezembro','conta_acumulado'];
const linhaMap = {};
result.forEach(item => { linhaMap[`${item.dre_linha_seq}_${item.cnpj_raiz}`] = item; });
function parsePercFormula(formula) {
  if (!formula || !formula.startsWith('PERC(')) return null;
  const match = formula.match(/PERC\(#L(\d+)\/#L(\d+)\)/);
  if (!match) return null;
  return { numerador: parseInt(match[1]), denominador: parseInt(match[2]) };
}
result.forEach(item => {
  if (item.perc_ref === '#L%%' && item.dre_linha_valor) {
    const formula = parsePercFormula(item.dre_linha_valor);
    if (formula) {
      const num = linhaMap[`${formula.numerador}_${item.cnpj_raiz}`];
      const den = linhaMap[`${formula.denominador}_${item.cnpj_raiz}`];
      if (num && den && num.perc_ref !== '#L%%' && den.perc_ref !== '#L%%') {
        colunas.forEach(col => { item[col] = den[col] === 0 ? 0 : (num[col]||0)/(den[col]||1)*100; });
      }
    }
  }
});
result.forEach(item => {
  const percRef = item.perc_ref;
  if (!percRef || percRef === '') { item.conta_perc = null; }
  else if (percRef === '#L%') { item.conta_perc = 100; }
  else if (percRef === '#L%%') { item.conta_perc = null; }
  else if (percRef.startsWith('#L')) {
    const refSeq = parseInt(percRef.replace('#L',''),10);
    const linhaRef = linhaMap[`${refSeq}_${item.cnpj_raiz}`];
    if (!linhaRef) { item.conta_perc = null; }
    else if (linhaRef.conta_acumulado === 0) { item.conta_perc = 0; }
    else { item.conta_perc = (item.conta_acumulado / linhaRef.conta_acumulado) * 100; }
  } else { item.conta_perc = null; }
  delete item.dre_linha_valor;
});
return result;

